let parts = msg.topic.split("/");
let room = parts[1];

msg.measurement = "environment";

msg.payload = [
    {
        temperature: Number(msg.payload.temperature),
        humidity: Number(msg.payload.humidity),
        pressure: Number(msg.payload.pressure),
        light: Number(msg.payload.light),
        altitude: Number(msg.payload.altitude)
    },
    {
        room: room
    }
];

return msg;

msg.topic = "MQTT alert - " + msg.deviceName + " offline";
msg.payload =
    "Device: " + msg.deviceName +
    "\nTopic: " + msg.originalTopic +
    "\nStatus: offline";

return msg;

let originalTopic = msg.topic;
let parts = originalTopic.split("/");
let deviceName = parts[1] || "unknown device";

msg.deviceName = deviceName;
msg.originalTopic = originalTopic;

if (msg.payload === "offline") {
    return msg;
}

if (msg.payload === "online") {
    msg.reset = true;
    return msg;
}

return null;
